const raw = $.steps.listFlows.output || '';
const parts = raw.split('---SEPARATOR---');
const flowLines = (parts[1] || '').trim().split('\n').filter(Boolean);

const flows = [];
flowLines.forEach(line => {
  try {
    const f = JSON.parse(line);
    flows.push(f);
  } catch(e) {}
});

let summary = '';
flows.forEach((f, i) => {
  summary += (i + 1) + '. ' + (f.name || f.key || f.file) + '\n';
  summary += '   Key: ' + (f.key || 'N/A') + '\n';
  summary += '   Steps: ' + (f.stepCount || 0) + ' | Inputs: ' + (f.inputCount || 0) + '\n';
  if (f.description) summary += '   ' + f.description.slice(0, 150) + '\n';
  if (f.source && f.source.platform) summary += '   Source: ' + f.source.platform + ' #' + (f.source.id || '') + '\n';
  summary += '\n';
});

return { flows, flowCount: flows.length, summary: summary.slice(0, 25000) };

const d = $.steps.parseFlowList.output;
const now = new Date().toISOString().split('T')[0];

let prompt = 'You are a workflow analyst. Categorize and summarize the following One CLI workflow inventory.\n\n';
prompt += 'DATE: ' + now + '\n';
prompt += 'TOTAL WORKFLOWS: ' + d.flowCount + '\n\n';
prompt += 'WORKFLOWS:\n' + d.summary + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Categorize each workflow (e.g., AI/Research, Email/Communication, Data/Analytics, Development, Social Media, etc.)\n';
prompt += '- Identify any duplicate or overlapping workflows\n';
prompt += '- Suggest gaps — useful workflows that are missing\n';
prompt += '- Provide overall inventory health assessment\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "categories": [{ "name": "Category", "count": 0, "workflows": ["workflow name"] }],\n';
prompt += '  "duplicates": [{ "workflows": ["name1", "name2"], "reason": "why similar" }],\n';
prompt += '  "gaps": ["suggested workflow 1"],\n';
prompt += '  "healthScore": "excellent|good|fair|needs-attention",\n';
prompt += '  "summary": "2-3 sentence inventory overview",\n';
prompt += '  "stats": { "totalWorkflows": 0, "categories": 0, "avgStepsPerFlow": 0 }\n';
prompt += '}';

return { prompt, date: now };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { categories: [], duplicates: [], gaps: [], healthScore: 'unknown', summary: raw, stats: {} }; }

const ai = $.steps.parseAI.output;
const d = $.steps.parseFlowList.output;
const date = $.steps.buildPrompt.output.date;

let report = 'ONE CLI WORKFLOW INVENTORY\n';
report += '========================\n';
report += 'Date: ' + date + '\n';
report += 'Total Workflows: ' + d.flowCount + '\n';
report += 'Health Score: ' + (ai.healthScore || 'N/A') + '\n\n';

if (ai.summary) {
  report += 'SUMMARY\n-------\n' + ai.summary + '\n\n';
}

if (ai.categories && ai.categories.length > 0) {
  report += 'CATEGORIES\n----------\n';
  ai.categories.forEach(cat => {
    report += '\n' + cat.name + ' (' + cat.count + ' workflows):\n';
    (cat.workflows || []).forEach(w => { report += '  - ' + w + '\n'; });
  });
  report += '\n';
}

if (ai.duplicates && ai.duplicates.length > 0) {
  report += 'POTENTIAL DUPLICATES\n-------------------\n';
  ai.duplicates.forEach((d, i) => {
    report += (i + 1) + '. ' + (d.workflows || []).join(' / ') + '\n';
    report += '   Reason: ' + d.reason + '\n';
  });
  report += '\n';
}

if (ai.gaps && ai.gaps.length > 0) {
  report += 'SUGGESTED GAPS\n--------------\n';
  ai.gaps.forEach((g, i) => { report += (i + 1) + '. ' + g + '\n'; });
  report += '\n';
}

report += 'FULL WORKFLOW LISTING\n--------------------\n';
report += d.summary;

return { report, fileName: 'one-cli-inventory-' + date + '.txt' };

const ai = $.steps.parseAI.output;
const d = $.steps.parseFlowList.output;
const date = $.steps.buildPrompt.output.date;

const healthEmoji = { excellent: ':star:', good: ':white_check_mark:', fair: ':ok:', 'needs-attention': ':warning:' };

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Workflow Inventory Report', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Date:* ' + date + ' | *Total workflows:* ' + d.flowCount + ' | *Health:* ' + (healthEmoji[ai.healthScore] || '') + ' ' + (ai.healthScore || 'unknown') } });
blocks.push({ type: 'divider' });

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.summary.slice(0, 2900) } });
  blocks.push({ type: 'divider' });
}

if (ai.categories && ai.categories.length > 0) {
  let catText = '*Categories:*\n';
  ai.categories.forEach(cat => {
    catText += '*' + cat.name + '*: ' + cat.count + ' workflows\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: catText.slice(0, 2900) } });
}

if (ai.gaps && ai.gaps.length > 0) {
  let gapText = ':bulb: *Suggested additions:*\n';
  ai.gaps.slice(0, 5).forEach((g, i) => { gapText += (i + 1) + '. ' + g + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: gapText } });
}

if (ai.duplicates && ai.duplicates.length > 0) {
  let dupText = ':warning: *Potential duplicates:*\n';
  ai.duplicates.slice(0, 3).forEach((d, i) => {
    dupText += (i + 1) + '. ' + (d.workflows || []).join(' / ') + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: dupText } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Inventory saved to Google Drive | Powered by Claude AI | One CLI' }] });

const fallback = 'Workflow Inventory: ' + d.flowCount + ' workflows - Health: ' + (ai.healthScore || 'unknown');
return { blocks, fallback };
